let parsedData;
try {
  const status = $json.status;
  const message = $json.message || '';
  if (status === 401 || status === 403) {
    throw new Error('Invalid API Key');
  }
  if (status === 400) {
    throw new Error('Invalid Prompt or Model Arguments');
  }
  if (status === 429) {
    throw new Error('AI Request failed: Rate limit or daily quota exceeded (429)');
  }
  if (status && status !== 200) {
    throw new Error(`AI Request failed with status ${status}: ${message}`);
  }

  const responseText = $json.candidates?.[0]?.content?.parts?.[0]?.text;
  if (!responseText) {
    throw new Error('Gemini API returned an empty or malformed response structure.');
  }
  parsedData = JSON.parse(responseText);

  return {
    success: true,
    resumeProfile: parsedData
  };
} catch (e) {
  return {
    success: false,
    error: e.message || 'An unexpected error occurred during resume parsing.'
  };
}
